#!/usr/bin/env node

import { existsSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { spawnSync } from 'node:child_process';

const here = dirname(fileURLToPath(import.meta.url));
const packageRoot = resolve(here, '..');
const candidates = [
  resolve(packageRoot, 'polyglot/target/release/gnexec'),
  resolve(packageRoot, 'polyglot/target/release/gnexec.exe'),
  resolve(packageRoot, 'polyglot/target/release/monster'),
  resolve(packageRoot, 'polyglot/target/release/monster.exe'),
];

const binary = candidates.find((candidate) => existsSync(candidate));

if (!binary) {
  process.stderr.write(
    'gnexec: native binary not installed; install from a release artifact or build with `pnpm --dir open-source/gnosis run monster:build`.\n',
  );
  process.exit(127);
}

const result = spawnSync(binary, process.argv.slice(2), { stdio: 'inherit' });
if (result.error) {
  throw result.error;
}
process.exit(result.status ?? 1);
